INSERT INTO public.news (id, title, slug, summary, content, cover_image_url, category, match_id, author, published_at, created_at, ai_generated, generation_meta) VALUES ('52803612-beec-4ee8-9b67-538ff342cb45', '包包的13-7首胜，NJU压住ZywOo', 'recap-282f886b', '小组赛 第一轮，包包的 在 de_ancient 以 13-7 取胜。NJU 28 杀、4 次首杀，半场 8-4 后把节奏握住。', '小组赛 第一轮，包包的 打 vitALIty，最后 包包的 在 de_ancient 用 13-7 把比赛收掉。这个比分乍一看是数字，细看是性格：上半场 8-4，下半场 5-3。你以为这只是 BO1 的一张图，我跟你说，这里面有队伍的脾气，有选手的手感，也有那种“弹幕刚打完不可能吧，下一秒就真来了”的抽象。

包包的赢得不算花，但非常实在。手枪局分布是 1-1，eco 胜利是 0-0，force 胜利是 0-0。这些数字看起来干巴，落到服务器里就是买枪选择、道具余量和残局站位。打 CS 不是写诗，但有时候一波默认控图打顺了，也确实像四个字：水到渠成。

NJU 交出 28-10，ADR 149.3，rating 2.15，4 次首杀，爆头率 53.0%，这是本场最亮的那盏灯。vitALIity的ZywOo本人 也有 25 杀、ADR 104.5，不是在旁边敲木鱼，是实打实把第二火力点接住了。幸运丶 再补 15 杀，队伍的火力层次就出来了。MVP 给 NJU 没什么争议，理由也很直白：rating 2.15 + 28 击杀 + 0 残局胜利 + 爆头率 53.0%。我知道有人要看 rating，有人要看击杀，有人只信关键回合；这场最有意思的是，这几项基本能对上。

第 18 回合是五杀回合，vitALIity的ZywOo本人拿到 5 杀；第 3 回合是四杀回合，NJU拿到 4 杀。这些回合不是锦上添花，是把比赛方向拽歪的手。尤其是那种四杀、五杀，你别管是不是对面送了，能把送到嘴边的分吃干净，本身就是职业病里的好病。

残局这块也有说法：第 9 回合 幸运丶 打出 1v1 残局胜利，第 17 回合 vitALIity的Ropz本人 打出 1v1 残局胜利。残局最折磨人的地方在于，它不像爆头率那么好看，也不像首杀那么响，它是全队都停下来看你一个人写答案。写对了，队友说 nice；写错了，回放能把人看老三岁。

第 3 回合，NJU 用 M4A4 带走 狗将军66，这是一次四杀；第 4 回合，幸运丶 用 M4A1 带走 vitALIity的ZywOo本人，这是一次混烟击杀；第 4 回合，ArcTra1 用 MAG-7 带走 vitALIity的Ropz本人，这是一次混烟击杀。这些镜头拿出来不是为了凑热闹，是为了说明这场的击杀质量并不低。混烟、闪光配合、四杀回合，全都有。你看，CS 有时候就是这么不讲武德：你以为烟后没人，对面已经把准星放在你的名字上了。

所以这场写到最后，包包的赢的是一个完整度。vitALIty不是没有单点回应，但回应太散，散到没法变成连续回合。包包的这边该有人站出来的时候有人站出来，该把优势回合收掉的时候也没有手软。古人说行百里者半九十，放到这张图就是：打到最后一分之前，都别急着开香槟；但包包的今天至少把瓶盖拧开得很稳。', NULL, '战报', '282f886b-b320-4e8a-977e-82cc8ee3d50a', 'ALAST 解说团', '2026-04-26 05:12:51.708124+08', '2026-04-26 05:12:51.708124+08', true, '{"model": "gpt-5.5-codex-offline", "warnings": [], "facts_hash": "10c7a32be3565114c723689224aa48bd0169d5a2fbc3ca93fe904d9ca6ae96f7", "retry_count": 0, "generated_at": "2026-04-26T07:37:49.249Z", "prompt_version": "offline-v1-machine-inspired-cn-terms"}');
INSERT INTO public.news (id, title, slug, summary, content, cover_image_url, category, match_id, author, published_at, created_at, ai_generated, generation_meta) VALUES ('41055744-952b-4223-bdf4-d117d0c3e4d8', '英特尔13-10力克105 Thieves', 'recap-57803faf', '小组赛 第一轮，英特尔首席科学家 在 unknown 以 13-10 取胜。关键回合处理更稳，半场 0-0 后把节奏握住。', '小组赛 第一轮这场 105 Thieves 对 英特尔首席科学家，数据包给出的画面很干净，也很冷：地图名缺失，最终比分是 13-10，英特尔首席科学家 把这一分拿走。你说这像不像一张只剩比分的录像带，导播把镜头掐了，但计分板还亮着，亮得人没法装作没看见。

从结果看，105 Thieves没有把比赛拖进最后的长盘拉扯，英特尔首席科学家在关键分处理上更像知道自己要什么。没有选手明细、没有击杀轨迹、没有残局记录，反而让这场比赛变成最朴素的 CS：谁先把 13 个回合攒够，谁就从服务器里走出来。

我知道你们要说，没数据怎么聊？能聊。比分就是最硬的证词。10-13不是玄学，它说明英特尔首席科学家至少在两个长回合段里把经济、站位和补枪都接住了；105 Thieves也不是没有机会，只是机会没有被写成回合。下一次如果这两队再碰，最好把 demo 也交出来，不然观众只能对着比分脑补，太残忍了。

这篇战报缺少更细的击杀和选手明细，所以只能把镜头按在比分上看。英特尔首席科学家的胜利不是靠一句“状态好”就能糊弄过去的，13-10说明他们在长盘里把容错率控制住了；105 Thieves的问题也很直接，回合没有连续性，前一分刚看到希望，后一分就又被打回经济重置。

我知道你们要说，这种比赛最难写，因为没有一个五杀、没有一个残局胜利可以直接拎出来当封面。但 CS 的底层逻辑有时候就这么朴素：谁少犯错，谁多补一枪，谁在中后段敢把道具交出去，谁就拿走胜利。英特尔首席科学家这一场就是把朴素两个字打成了结果，没那么花，但够硬。

从观感上说，这种没有明星数据托底的胜利，反而更考验队伍底盘。它不像五杀那样一声锣响全场都知道，也不像加时那样天然带着戏剧性，它更接近一盘慢慢拧紧的螺丝：默认控图多拿一秒，补枪多快半步，残局少露一个侧身，最后比分就从五五开变成了对手追不回来的差距。英特尔首席科学家13-10这场至少做到了这一点。', NULL, '战报', '57803faf-8a90-450d-995d-121ac3c0d8ab', 'ALAST 解说团', '2026-04-26 05:12:51.71204+08', '2026-04-26 05:12:51.71204+08', true, '{"model": "gpt-5.5-codex-offline", "warnings": [], "facts_hash": "1a974fcc15780a7a7691240df303184822885bc285dcf45d2e9e6009c754e780", "retry_count": 0, "generated_at": "2026-04-26T07:37:49.249Z", "prompt_version": "offline-v1-machine-inspired-cn-terms"}');
INSERT INTO public.news (id, title, slug, summary, content, cover_image_url, category, match_id, author, published_at, created_at, ai_generated, generation_meta) VALUES ('8ed75f97-e11b-4434-bea8-1744fa24abd1', 'NTR13-6拿下冠军，真的爆丸五杀', 'recap-25914584', '小组赛 第一轮，NTR 在 de_mirage 以 13-6 取胜。真的爆丸 27 杀、2 次首杀，半场 5-7 后把节奏握住。', '小组赛 第一轮，冠军 打 NTR，最后 NTR 在 de_mirage 用 13-6 把比赛收掉。这个比分乍一看是数字，细看是性格：上半场 5-7，下半场 1-6。你以为这只是 BO1 的一张图，我跟你说，这里面有队伍的脾气，有选手的手感，也有那种“弹幕刚打完不可能吧，下一秒就真来了”的抽象。

NTR赢得不算花，但非常实在。手枪局分布是 1-1，eco 胜利是 0-0，force 胜利是 0-0。这些数字看起来干巴，落到服务器里就是买枪选择、道具余量和残局站位。打 CS 不是写诗，但有时候一波默认控图打顺了，也确实像四个字：水到渠成。

