INSERT INTO public.news (id, title, slug, summary, content, cover_image_url, category, match_id, author, published_at, created_at, ai_generated, generation_meta) VALUES ('15f91f46-5d24-446c-9953-8e23c1b6480c', '包包的加时16-12掀翻英特尔', 'recap-b9df164c', '小组赛 第三轮，包包的 在 de_mirage 以 16-12 取胜。NJU 29 杀、3 次首杀，半场 4-8 后把节奏握住。', '小组赛 第三轮，英特尔首席科学家 打 包包的，最后 包包的 在 de_mirage 用 16-12 把比赛收掉。这个比分乍一看是数字，细看是性格：上半场 4-8，下半场 8-8，加时 0-4。你以为这只是 BO1 的一张图，我跟你说，这里面有队伍的脾气，有选手的手感，也有那种“弹幕刚打完不可能吧，下一秒就真来了”的抽象。

