INSERT INTO public.news (id, title, slug, summary, content, cover_image_url, category, match_id, author, published_at, created_at, ai_generated, generation_meta) VALUES ('9a3b110a-6502-4d29-b549-19f424021e3c', '痱子可烂13-11险胜达哥队', 'recap-d7accda8', '小组赛 第一轮，痱子可烂 在 de_inferno 以 13-11 取胜。我的牙签久经沙场 19 杀、2 次首杀，半场 5-7 后把节奏握住。', '小组赛 第一轮，达哥说的对不队 打 痱子可烂，最后 痱子可烂 在 de_inferno 用 13-11 把比赛收掉。这个比分乍一看是数字，细看是性格：上半场 5-7，下半场 6-6。你以为这只是 BO1 的一张图，我跟你说，这里面有队伍的脾气，有选手的手感，也有那种“弹幕刚打完不可能吧，下一秒就真来了”的抽象。

痱子可烂赢得不算花，但非常实在。手枪局分布是 1-1，eco 胜利是 0-0，force 胜利是 0-0。这些数字看起来干巴，落到服务器里就是买枪选择、道具余量和残局站位。打 CS 不是写诗，但有时候一波默认控图打顺了，也确实像四个字：水到渠成。

我的牙签久经沙场 交出 19-13，ADR 93.6，rating 1.47，2 次首杀，爆头率 63.0%，这是本场最亮的那盏灯。TheXiu 也有 20 杀、ADR 80.8，不是在旁边敲木鱼，是实打实把第二火力点接住了。人狠话不多 再补 20 杀，队伍的火力层次就出来了。MVP 给 我的牙签久经沙场 没什么争议，理由也很直白：rating 1.47 + 19 击杀 + 0 残局胜利 + 爆头率 63.0%。我知道有人要看 rating，有人要看击杀，有人只信关键回合；这场最有意思的是，这几项基本能对上。

第 2 回合是强起残局，Captain⚡︎⚡︎打成 1v2，结果是胜利；第 21 回合是强起残局，TheXiu打成 1v2，结果是胜利；第 3 回合是四杀回合，火舞旋风🌪拿到 4 杀。这些回合不是锦上添花，是把比赛方向拽歪的手。尤其是那种四杀、五杀，你别管是不是对面送了，能把送到嘴边的分吃干净，本身就是职业病里的好病。

残局这块也有说法：第 2 回合 Captain⚡︎⚡︎ 打出 1v2 残局胜利，第 21 回合 TheXiu 打出 1v2 残局胜利，第 9 回合 TheXiu 打出 1v1 残局胜利。残局最折磨人的地方在于，它不像爆头率那么好看，也不像首杀那么响，它是全队都停下来看你一个人写答案。写对了，队友说 nice；写错了，回放能把人看老三岁。

第 3 回合，火舞旋风🌪 用 Galil AR 带走 如风过境，这是一次四杀；第 5 回合，北杏 用 AK-47 带走 你的网友chn，这是一次混烟击杀；第 5 回合，我的牙签久经沙场 用 M4A4 带走 TheXiu，这是一次混烟击杀。这些镜头拿出来不是为了凑热闹，是为了说明这场的击杀质量并不低。混烟、闪光配合、四杀回合，全都有。你看，CS 有时候就是这么不讲武德：你以为烟后没人，对面已经把准星放在你的名字上了。', NULL, '战报', 'd7accda8-1bfe-4e75-ae3a-8149cbb6093d', 'ALAST 解说团', '2026-04-26 05:12:51.713932+08', '2026-04-26 05:12:51.713932+08', true, '{"model": "gpt-5.5-codex-offline", "warnings": [], "facts_hash": "db2828f59d1e34ae40cac1fc75e39c0557541b90501271aaff32b097c064a298", "retry_count": 0, "generated_at": "2026-04-26T07:37:49.249Z", "prompt_version": "offline-v1-machine-inspired-cn-terms"}');


